import React, { useEffect, useState } from "react";
import EventList from "../components/EventList";
import api from "../api";

const BrowseEvents = () => {
  const [events, setEvents] = useState([]);
  const [loading, setLoading] = useState(true);
  const [search, setSearch] = useState("");
  const [error, setError] = useState(null);

  // useEffect(() => {
  //   const fetchEvents = async () => {
  //     try {
  //       setLoading(true);
  //       const token = localStorage.getItem("token");
  //       const response = await api.get("/events", {
  //         headers: {
  //           Authorization: `Bearer ${token}`,
  //         },
  //       });

  //       setEvents(response.data);
  //     } catch (err) {
  //       console.error("Fetch events error:", err);
  //       setError("Failed to fetch events");
  //     } finally {
  //       setLoading(false);
  //     }
  //   };

  //   fetchEvents();
  // }, []);

  // Filter events safely
  const filteredEvents = events.filter((event) => {
    const eventName = event?.name?.toLowerCase() || "";
    const organiserName =
      `${event?.organiser?.firstName || ""} ${event?.organiser?.lastName || ""}`.toLowerCase();
    const searchValue = search.toLowerCase() || "";

    return eventName.includes(searchValue) || organiserName.includes(searchValue);
  });

  return (
    <div className="container mx-auto p-4">
      <h1 className="text-2xl font-bold mb-4">Browse Events</h1>

      <input
        type="text"
        placeholder="Search events or organisers..."
        className="border p-2 mb-4 w-full"
        value={search}
        onChange={(e) => setSearch(e.target.value)}
      />

      {loading && <p>Loading events...</p>}
      {error && <p className="text-red-500">{error}</p>}

      {!loading && !error && <EventList events={filteredEvents} />}
    </div>
  );
};

export default BrowseEvents;
